using UnityEngine;
using Climbing;
using UnityEditor;

public class ClimbFixer
{
    public static string Fix()
    {
        GameObject pm = GameObject.Find("Player_New/PlayerModel");
        if (pm == null) return "Player_New/PlayerModel not found";

        ClimbController cc = pm.GetComponent<ClimbController>();
        if (cc == null) return "ClimbController not found";

        // Use reflection to set private serializable fields if needed, 
        // but looking at the code, they are just [SerializeField] private.
        // We can use SerializedObject for a clean way to set them.
        SerializedObject so = new SerializedObject(cc);
        so.FindProperty("AutoSearchBones").boolValue = true;
        so.ApplyModifiedProperties();

        // Also check Rigidbody - character in air might be due to gravity or isKinematic
        Rigidbody rb = pm.GetComponent<Rigidbody>();
        string rbInfo = "";
        if (rb != null) {
            rb.useGravity = true;
            rb.isKinematic = false;
            rb.collisionDetectionMode = CollisionDetectionMode.Continuous;
            rbInfo = $" | Rigidbody: useGravity={rb.useGravity}, isKinematic={rb.isKinematic}";
        }

        return "Successfully enabled AutoSearchBones on ClimbController" + rbInfo;
    }
}
